<template>
    <div class="widget-card dashboard-boxes graph-widget-box bg-white mt-2 mb-4">
        <div class="widget-header graph-widget-heading float-left w-100">
            <div class="widget-title">
                <em class="fa fa-calendar"></em> {{ $t('SevenDaysReport') }}
            </div>
        </div>

        <div id="WorkDateReport" class="chart-container"></div>


    </div>
</template>

<script>
import * as Plotly from 'plotly.js-dist';
import { analyticsService } from '../../../../services/analyticsService';

export default {
    name: 'AgentPerformance',
    data() {
        return {
            loading: false,
            StatusData: [],

        };
    },

    mounted() {
        var vm = this;
        vm.loadData();
    },
    methods: {
        async loadData() {
            var vm = this;
            vm.loading = true;
            try {
                //const url = `ClientId=`;
                const response = await analyticsService.GetWorkdateStatusData();
                if (response && response.data && response.data.result) {

                    let result = response.data.result;

                    // 1️⃣ If result is a string, parse it
                    if (typeof result === 'string') {
                        result = JSON.parse(result);
                    }

                    // 2️⃣ Now result should be an array → take first item
                    if (Array.isArray(result) && typeof result[0] === 'string') {
                        result = JSON.parse(result[0]);
                    }

                    // 3️⃣ Now you finally have the object
                    const dataArray = result.Data || [];

                    const xValues = dataArray.map(d => d.workdate);

                    const statusKeys = Object.keys(dataArray[0]).filter(
                        key => key !== 'workdate' && key !== 'TotalRecords'
                    );

                    const traces = statusKeys.map(status => ({
                        x: xValues,
                        y: dataArray.map(d => d[status]),
                        name: status,
                        type: 'bar'
                    }));

                    var data = traces;

                    vm.drawChart(data);

                }

            } catch (error) {
                console.error('Error loading total revenue trend:', error);
            } finally {
                vm.loading = false;
            }
        },
        drawChart(Data) {
            // var trace1 = {
            //     x: ['giraffes', 'orangutans', 'monkeys'],
            //     y: [20, 14, 23],
            //     name: 'SF Zoo',
            //     type: 'bar'
            // };

            // var trace2 = {
            //     x: ['giraffes', 'orangutans', 'monkeys'],
            //     y: [12, 18, 29],
            //     name: 'LA Zoo',
            //     type: 'bar'
            // };

            // var data = [trace1, trace2];

            const layout = {
                barmode: 'group',
                margin: { t: 60, b: 60, l: 50, r: 30 },
                uniformtext: { minsize: 8, mode: 'hide' }
            };

            Plotly.newPlot('WorkDateReport', Data, layout, { responsive: true, displayModeBar: false });
        }
    }
};
</script>


