<template>
  <div class="widget-card dashboard-boxes graph-widget-box bg-white">
    <div class="widget-header graph-widget-heading float-left w-100">
      <div class="widget-title">
        <em class="fas fa-file-invoice-dollar"></em>{{ $t('BillsvsRevenue') }}
      </div>
    </div>

    <div v-if="loading" class="loading">Loading...</div>
    <div v-else id="billsVsRevenueChart" class="chart-container"></div>

    <div class="mini-stats">
      <div class="mini-stat">
        <div class="mini-stat-value">{{ $n(BillRevenueRatio) }}</div>
        <div class="mini-stat-label">{{ $t('AvgBillRevenueRatio') }}</div>
      </div>
      <div class="mini-stat">
        <div class="mini-stat-value">{{ $n(TotalBills) }}</div>
        <div class="mini-stat-label">{{ $t('TotalBills') }}</div>
      </div>
    </div>
  </div>
</template>

<script>
import { analyticsService } from '../../../../services/analyticsService';
import * as Plotly from 'plotly.js-dist';

export default {
  name: 'BillsVsRevenueWidget',
  data() {
    return {
      loading: false,
      quarters: null,
      revenues: null,
      bills: null
    };
  },
  mounted() {
    this.loadData();
  },
  props: {
    QuarterlyTrendAnalysisData: {
      type: Array,
      default: () => []
    },
    TotalBills: {
      type: Number,
    },
    BillRevenueRatio: {
      type: Number,
    }
  },
  methods: {
    async loadData() {
      //debugger
      var vm = this;
      vm.loading = true;
      try {
        vm.quarters = vm.QuarterlyTrendAnalysisData.map(d => d.Quarter_Label);
        vm.bills = vm.QuarterlyTrendAnalysisData.map(d => d.Total_Bills);
        vm.revenues = vm.QuarterlyTrendAnalysisData.map(d => d.Total_Revenue / 10000);
        vm.drawChart();

      } catch (error) {
        console.error('Error loading total revenue trend:', error);
      } finally {
        vm.loading = false;
      }
    },
    drawChart() {
      //if (!data || !data.quarters) return;

      const trace1 = {
        x: this.quarters,
        y: this.bills,
        name: 'Bills',
        type: 'bar',
        marker: { color: '#3b82f6' }
      };

      const trace2 = {
        x: this.quarters,
        y: this.revenues,
        name: 'Revenue',
        type: 'scatter',
        mode: 'lines+markers',
        yaxis: 'y2',
        line: { color: '#f59e0b', width: 3 }
      };

      const layout = {
        margin: { t: 30, b: 60, l: 50, r: 50 },
        paper_bgcolor: 'transparent',
        plot_bgcolor: 'transparent',
        height: 280,
        xaxis: {
          title: { text: 'Quarter' },
          tickangle: -45,
          gridcolor: '#f1f1f1',
          showgrid: true
        },
        yaxis: {
          title: { text: 'Number of Bills' },
          tickformat: '.2s',
          gridcolor: '#f1f1f1',
          showgrid: true,
          titlefont: { color: '#8b5cf6' }
        },

        yaxis2: {
          title: { text: 'Revenue ($)' },
          overlaying: 'y',
          side: 'right',
          tickformat: '.2s',
          gridcolor: 'rgba(245, 158, 11, 0.1)',
          titlefont: { color: '#f59e0b' }
        },

      };

      Plotly.newPlot('billsVsRevenueChart', [trace1, trace2], layout, { responsive: true, displayModeBar: false });
    }
  }
};
</script>
