<template>
  <div class="widget-card dashboard-boxes graph-widget-box bg-white mt-2 mb-4">
    <loader :is-visible="isLoading"></loader>
    <div class="widget-header graph-widget-heading float-left w-100">
      <div class="widget-title">
        <em class="fas fa-users"></em>{{ $t('TopCustomersbyRevenue') }}
      </div>
    </div>

    <div class="revenue-controls p-3">
      <button v-for="sort in sortOptions" :key="sort.id" :class="['revenue-btn', { active: selectedSort === sort.id }]"
        @click="selectSort(sort)">
        {{ sort.label }}
      </button>
    </div>

    <div class="listing p-3">
      <div class="table-responsive">
        <table class="table table-bordered mt-0">
          <thead class="thead-bg">
            <tr>
              <th style="width:100px;">{{ $t('Rank') }}</th>
              <th>{{ $t('Customer') }}</th>
              <th style="width:250px;">{{ $t('Revenue') }}</th>
              <th style="width:250px;">YoY {{ $t('Growth') }}</th>
            </tr>
          </thead>
          <tbody>
            <tr v-for="(customer, index) in customers" :key="index">
              <td>{{ index + 1 }}</td>
              <td>{{ customer.name }}</td>
              <td class="text-right">{{ formatCurrency(customer.revenue) }}</td>
              <td class="text-right">{{ formatPercent(customer.growth) }}</td>
            </tr>
          </tbody>
        </table>
      </div>
    </div>

  </div>
</template>

<script>
import { analyticsService } from '../../../../services/analyticsService';

export default {
  name: 'TopCustomersWidget',
  data() {
    return {

      customers: [],
      sortField: 'Current_Revenue',
      selectedSort: 'revenue_desc',
      sortOrder: 'desc',
      sortOptions: [
        { id: 'revenue_desc', label: 'Sort by Revenue (High to Low)', name: 'Current_Revenue' },
        { id: 'revenue_asc', label: 'Sort by Revenue (Low to High)', name: 'Current_Revenue' },
        { id: 'growth_desc', label: 'Sort by Growth (High to Low)', name: 'Growth_Percentage' },
        { id: 'growth_asc', label: 'Sort by Growth (Low to High)', name: 'Growth_Percentage' },
        { id: 'ClientName', label: 'Sort by Name (A-Z)', name: 'ClientName' }
      ],
      isLoading: false,
      originalCustomers: [], // ✅ store backend data once


    };
  },
  mounted() {
    this.loadData();
  },

  methods: {
    async loadData() {

      this.isLoading = true;

      try {        

        var PeriodType = '1_YEAR';
        const url = `PeriodType=${PeriodType}&SortColumn=${this.sortField}&SortDirection=${this.sortOrder}`;
        const response = await analyticsService.GetClientRevenueGrowth(url);
        if (response && response.data && response.data.result) {
          // Handle double-encoded JSON: result is a string containing an array with a JSON string
          let resultData = response.data.result;

          // First parse: convert string to array
          if (typeof resultData === 'string') {
            resultData = JSON.parse(resultData);
          }

          // Second parse: extract the JSON string from the array and parse it
          if (Array.isArray(resultData) && resultData.length > 0 && typeof resultData[0] === 'string') {
            resultData = JSON.parse(resultData[0]);
          }

          // Map the API response to the expected format
          // this.customers = (Array.isArray(resultData) ? resultData : []).map(customer => ({
          //   name: customer.ClientName || '',
          //   revenue: customer.Current_Revenue || 0,
          //   growth: customer.Growth_Percentage || 0,
          //   previousRevenue: customer.Previous_Revenue || 0,
          //   revenueDifference: customer.Revenue_Difference || 0,
          //   growthTrend: customer.Growth_Trend || 'UP'
          // }));

          const mappedData = (Array.isArray(resultData) ? resultData : []).map(customer => ({
            name: customer.ClientName || '',
            revenue: customer.Current_Revenue || 0,
            growth: customer.Growth_Percentage || 0,
            previousRevenue: customer.Previous_Revenue || 0,
            revenueDifference: customer.Revenue_Difference || 0,
            growthTrend: customer.Growth_Trend || 'UP'
          }));

          // ✅ store original data
          this.originalCustomers = mappedData;

          // ✅ apply default sorting
          this.applySorting();
        }
      } catch (error) {
        console.error('Error loading top customers:', error);
      } finally {
        this.isLoading = false;
      }
    },

    applySorting() {

      let sorted = [...this.originalCustomers];

      switch (this.sortField) {

        case 'Current_Revenue':
          sorted.sort((a, b) =>
            this.sortOrder === 'desc'
              ? b.revenue - a.revenue
              : a.revenue - b.revenue
          );
          break;

        case 'Growth_Percentage':
          sorted.sort((a, b) =>
            this.sortOrder === 'desc'
              ? b.growth - a.growth
              : a.growth - b.growth
          );
          break;

        case 'ClientName':
          sorted.sort((a, b) =>
            this.sortOrder === 'desc'
              ? b.name.localeCompare(a.name)
              : a.name.localeCompare(b.name)
          );
          break;
      }

      this.customers = sorted;
    },
    selectSort(sort) {
      this.selectedSort = sort.id;
      this.sortField = sort.name;
      this.sortOrder = sort.id.includes('desc') ? 'desc' : 'asc';


      // ❌ remove API call
      // this.loadData();

      // ✅ local sorting only
      this.applySorting();
    },
    formatCurrency(value) {
      return new Intl.NumberFormat('en-US', { style: 'currency', currency: 'USD', minimumFractionDigits: 0 }).format(value);
    },
    formatPercent(value) {
      return `${value >= 0 ? '+' : ''}${value.toFixed(2)}%`;
    }
  }
};
</script>
