<template>
  <div class="widget-card dashboard-boxes graph-widget-box bg-white">
    <div class="widget-header graph-widget-heading float-left w-100">
      <div class="widget-title">
        <em class="fas fa-users"></em>{{ $t("UniqueClients") }} 
      </div>
    </div>

    <div v-if="loading" class="loading">Loading...</div>
    <div v-else id="uniqueClientsChart" class="chart-container"></div>

    <div class="mini-stats">
      <div class="mini-stat">
        <div class="mini-stat-value">{{ $n(PeakClients) }}</div>
        <div class="mini-stat-label">{{ $t('PeakClients') }}</div>
      </div>
      <div class="mini-stat">
        <div class="mini-stat-value">{{ $n(AverageClients) }}</div>
        <div class="mini-stat-label">{{ $t('AverageQuarterly') }}</div>
      </div>
    </div>
  </div>
</template>

<script>
import { analyticsService } from '../../../../services/analyticsService';
import * as Plotly from 'plotly.js-dist';

export default {
  name: 'UniqueClientsWidget',
  data() {
    return {
      loading: false,
      stats: null
    };
  },
  mounted() {
    this.loadData();
  },
  props: {
    QuarterlyTrendAnalysisData: {
      type: Array,
      default: () => []
    },
    PeakClients: {
      type: Number,
      default: null
    },
    AverageClients: {
      type: Number,
      default: null
    },
  },
  methods: {
    async loadData() {
      //debugger
      var vm = this;
      vm.loading = true;
      try {
        vm.quarters = vm.QuarterlyTrendAnalysisData.map(d => d.Quarter_Label);
        vm.revenues = vm.QuarterlyTrendAnalysisData.map(d => d.Unique_Clients);
        vm.drawChart();

      } catch (error) {
        console.error('Error loading total revenue trend:', error);
      } finally {
        vm.loading = false;
      }
    },
    drawChart() {
      //if (!data || !data.quarters || !data.values) return;

      const trace = {
        x: this.quarters,
        y: this.revenues,
        type: 'scatter',
        mode: 'lines+markers',
        fill: 'tozeroy',
        line: { color: '#ec4899', width: 3 },
        marker: { size: 6 }
      };

      const layout = {
        margin: { t: 30, b: 60, l: 50, r: 50 },
        paper_bgcolor: 'transparent',
        plot_bgcolor: 'transparent',
        height: 280
      };

      Plotly.newPlot('uniqueClientsChart', [trace], layout, { responsive: true, displayModeBar: false });
    }
  }
};
</script>

